Sliding Window.code:
int l = 0, best = 0;
for (int r = 0; r < n; r++) {
    // 1. Add nums[r] to the current window state
    state.add(nums[r]);

    // 2. Shrink the window from the left until it becomes valid again
    while (invalid(state)) {
        state.remove(nums[l]);
        l++;
    }

    // 3. Update the global optimum when the window is valid
    best = max(best, r - l + 1);
}

