// --- DFS (Bottom-Up State Passing) ---
int dfs(TreeNode* root) {
    if (!root) return 0;
    int left = dfs(root->left);
    int right = dfs(root->right);
    // Process state
    return max(left, right) + 1;
}

// --- BFS (Level Order) ---
queue<TreeNode*> q;
q.push(root);
while (!q.empty()) {
    int size = q.size();
    for (int i = 0; i < size; i++) {
        TreeNode* node = q.front();
        q.pop();
        if (node->left) q.push(node->left);
        if (node->right) q.push(node->right);
    }
}

Trie (Prefix Tree).code:
struct TrieNode {
    TrieNode* next[26] = {NULL};
    bool isEnd = false;

    // Prevent memory leaks in C++ interviews
    ~TrieNode() {
        for (TrieNode* node : next) {
            if (node != NULL) delete node;
        }
    }
};

void insert(TrieNode* root, string& word) {
    TrieNode* node = root;
    for (char c : word) {
        if (node->next[c - 'a'] == NULL) {
            node->next[c - 'a'] = new TrieNode();
        }
        node = node->next[c - 'a'];
    }
    node->isEnd = true;
}

Backtracking.code:
void backtrack(vector<int>& candidates, vector<int>& current, int target, int start) {
    if (target == 0) {
        result.push_back(current);
        return;
    }

    for (int i = start; i < candidates.size(); i++) {
        // Pruning: skip invalid states to save time
        if (target < candidates[i]) break;
        // Avoid duplicate combinations if elements are not unique
        if (i > start && candidates[i] == candidates[i - 1]) continue;

        current.push_back(candidates[i]);
        // Pass i instead of i+1 if elements can be reused
        backtrack(candidates, current, target - candidates[i], i + 1);
        current.pop_back();
    }
}

