Graph: Union-Find (DSU).code:
struct DSU {
    vector<int> parent;
    DSU(int n) {
        parent.resize(n);
        iota(parent.begin(), parent.end(), 0); // Initialize with 0 ~ n-1
    }

    int find(int i) {
        // Path Compression is mandatory for optimal complexity
        return parent[i] == i ? i : (parent[i] = find(parent[i]));
    }

    bool unite(int i, int j) {
        int root_i = find(i), root_j = find(j);
        if (root_i == root_j) return false; // Cycle detected

        parent[root_i] = root_j;
        return true;
    }
};

