vector<int> dist(n, INT_MAX);
// Min-heap storing {distance, node}
priority_queue<pair<int, int>, vector<pair<int, int>>, greater<>> pq;

dist[start] = 0;
pq.push({0, start});

while (!pq.empty()) {
    auto [d, u] = pq.top();
    pq.pop();

    // Lazy deletion: skip if we've already found a shorter path to u
    if (d > dist[u]) continue;

    for (auto& [v, weight] : graph[u]) {
        if (dist[u] + weight < dist[v]) {
            dist[v] = dist[u] + weight;
            pq.push({dist[v], v});
        }
    }
}

Segment Tree.code:
const int INVALID = -1;
// Highly recommended to allocate 4 * N space for the tree array

void update(vector<int>& tree, int node, int start, int end, int index, int val) {
    if (start == end) {
        tree[node] = val;
        return;
    }
    int mid = start + (end - start) / 2;
    if (index <= mid) update(tree, 2 * node, start, mid, index, val);
    else update(tree, 2 * node + 1, mid + 1, end, index, val);

    tree[node] = max(tree[2 * node], tree[2 * node + 1]);
}

int query(vector<int>& tree, int node, int start, int end, int l, int r) {
    if (r < start || l > end) return INVALID;
    if (l <= start && end <= r) return tree[node];

    int mid = start + (end - start) / 2;
    int left_res = query(tree, 2 * node, start, mid, l, r);
    int right_res = query(tree, 2 * node + 1, mid + 1, end, l, r);
    return max(left_res, right_res);
}

Digit DP.code:
long long memo[20][2][2][state_size];

long long dfs(int pos, bool limit, bool lead, int state, const string& num) {
    if (pos == num.size()) return 1; // Found a valid number
    if (memo[pos][limit][lead][state] != -1) return memo[pos][limit][lead][state];

    int up = limit ? num[pos] - '0' : 9;
    long long res = 0;

    for (int i = 0; i <= up; i++) {
        // Correctly propagate the 'limit' flag
        bool next_limit = limit && (i == up);
        // Handle 'lead zero' if it affects the digit state
        bool next_lead = lead && (i == 0);

        res += dfs(pos + 1, next_limit, next_lead, next_state, num);
    }
    return memo[pos][limit][lead][state] = res;
}

