// Check if the i-th bit is set in the mask
// if ((mask & (1 << i)) != 0)

// Set the i-th bit in the mask
// int next_mask = mask | (1 << i);

int dfs(int mask, int last_node) {
    if (mask == (1 << N) - 1) return 0; // All nodes visited
    if (memo[mask][last_node] != -1) return memo[mask][last_node];

    int best = INT_MAX;
    for (int i = 0; i < N; i++) {
        if ((mask & (1 << i)) == 0) { // If node 'i' is NOT visited
            int cost = graph[last_node][i] + dfs(mask | (1 << i), i);
            best = min(best, cost);
        }
    }
    return memo[mask][last_node] = best;
}
